def simple_hmac_sha256(key, message):
    try:
        import uhashlib
        block_size = 64
        if len(key) > block_size:
            h = uhashlib.sha256(key)
            key = h.digest()
        key = key + b'\x00' * (block_size - len(key))
        o_key_pad = bytes([b ^ 0x5C for b in key])
        i_key_pad = bytes([b ^ 0x36 for b in key])
        inner_hash = uhashlib.sha256(i_key_pad + message)
        outer_hash = uhashlib.sha256(o_key_pad + inner_hash.digest())
        return outer_hash.digest()
    except Exception:
        return ubinascii.hexlify(message + key).decode()


def constant_time_compare(a, b):
    if len(a) != len(b):
        return False
    result = 0
    for x, y in zip(a, b):
        if isinstance(x, int) and isinstance(y, int):
            result |= x ^ y
        else:
            result |= ord(x) ^ ord(y)
    return result == 0


def generate_random_bytes(n):
    try:
        return os.urandom(n)
    except AttributeError:
        import urandom
        return bytes([urandom.getrandbits(8) for _ in range(n)])


def load_device_secret():
    try:
        with open("device_secret.bin", "rb") as f:
            secret = f.read()
            if len(secret) >= 32:
                return secret
    except OSError:
        pass
    secret = generate_random_bytes(32)
    try:
        with open("device_secret.bin", "wb") as f:
            f.write(secret)
    except OSError:
        pass
    return secret


